package com.example.samlsp.controller;

import com.example.samlsp.saml.SamlAuthentication;
import com.example.samlsp.saml.SamlResponseProcessor;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.util.MultiValueMap;
import org.springframework.web.bind.annotation.*;

import java.net.URI;

@RestController
public class SamlAcsController {

    public static final String SESSION_AUTH_KEY = "SAML_AUTH";

    private final SamlResponseProcessor samlResponseProcessor;

    public SamlAcsController(SamlResponseProcessor samlResponseProcessor) {
        this.samlResponseProcessor = samlResponseProcessor;
    }

    @PostMapping(path = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<Void> acs(@RequestBody MultiValueMap<String, String> form,
                                    HttpServletRequest request) {
        String samlResponse = form.getFirst("SAMLResponse");
        String relayState = form.getFirst("RelayState");

        if (samlResponse == null || samlResponse.isBlank()) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).build();
        }

        SamlAuthentication auth = samlResponseProcessor.processBase64Response(samlResponse, request);

        HttpSession session = request.getSession(true);
        session.setAttribute(SESSION_AUTH_KEY, auth);
        session.setAttribute("SAML_NAME_ID", auth.getNameId());
        session.setAttribute("SAML_SESSION_INDEX", auth.getSessionIndex());
        session.setAttribute("SAML_ATTRIBUTES", auth.getAttributes());
        session.setAttribute("SAML_AUDIENCE", auth.getAudience());
        session.setAttribute("SAML_ISSUER", auth.getIssuer());

        URI target = URI.create((relayState != null && !relayState.isBlank()) ? relayState : "/");
        HttpHeaders headers = new HttpHeaders();
        headers.setLocation(target);
        return new ResponseEntity<>(headers, HttpStatus.FOUND);
    }

    @GetMapping("/auth/me")
    public ResponseEntity<Object> me(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        Object auth = session.getAttribute(SESSION_AUTH_KEY);
        if (auth == null) return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        return ResponseEntity.ok(auth);
    }

    @PostMapping("/auth/logout")
    public ResponseEntity<Void> logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();
        return ResponseEntity.noContent().build();
    }
}

