package com.example.samlsp.saml;

import jakarta.servlet.http.HttpServletRequest;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import org.w3c.dom.*;

import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.*;

@Component
public class SamlXmlParser {

    @Value("${saml.sp.entity-id:urn:example:sp}")
    private String spEntityId;

    @Value("${saml.expected-issuer:}")
    private String expectedIssuer;

    public SamlAuthentication parseAndValidate(String xml, HttpServletRequest request) {
        Document doc = parseSecurely(xml);

        Element responseEl = doc.getDocumentElement();
        Element assertionEl = firstElementByLocalName(doc, "Assertion");
        if (assertionEl == null) throw new SamlValidationException("Missing Assertion");

        String issuer = textOfFirst(assertionEl, "Issuer");
        if (issuer == null || issuer.isBlank()) issuer = textOfFirst(responseEl, "Issuer");

        if (expectedIssuer != null && !expectedIssuer.isBlank()) {
            if (issuer == null || !expectedIssuer.equals(issuer)) {
                throw new SamlValidationException("Unexpected Issuer");
            }
        }

        String nameId = extractNameId(assertionEl);
        if (nameId == null || nameId.isBlank()) throw new SamlValidationException("Missing NameID");

        String sessionIndex = extractSessionIndex(assertionEl);

        Conditions conditions = extractConditions(assertionEl);
        validateTimeWindow(conditions);

        String audience = extractAudience(assertionEl);
        if (audience != null && !audience.isBlank()) {
            if (!audience.equals(spEntityId)) {
                throw new SamlValidationException("Audience restriction does not match SP entityId");
            }
        }

        Map<String, List<String>> attributes = extractAttributes(assertionEl);

        return new SamlAuthentication(
                nameId,
                sessionIndex,
                issuer,
                audience,
                conditions.notBefore,
                conditions.notOnOrAfter,
                attributes
        );
    }

    private Document parseSecurely(String xml) {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            DocumentBuilder builder = dbf.newDocumentBuilder();
            return builder.parse(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
        } catch (Exception e) {
            throw new SamlValidationException("Failed to parse SAML XML", e);
        }
    }

    private void validateTimeWindow(Conditions c) {
        Instant now = Instant.now();
        if (c.notBefore != null && now.isBefore(c.notBefore.minusSeconds(60))) {
            throw new SamlValidationException("Assertion not yet valid");
        }
        if (c.notOnOrAfter != null && !now.isBefore(c.notOnOrAfter.plusSeconds(60))) {
            throw new SamlValidationException("Assertion expired");
        }
    }

    private String extractNameId(Element assertionEl) {
        Element subjectEl = firstElementByLocalName(assertionEl, "Subject");
        if (subjectEl == null) return null;
        Element nameIdEl = firstElementByLocalName(subjectEl, "NameID");
        if (nameIdEl == null) return null;
        String v = nameIdEl.getTextContent();
        return v == null ? null : v.trim();
    }

    private String extractSessionIndex(Element assertionEl) {
        Element authnStatementEl = firstElementByLocalName(assertionEl, "AuthnStatement");
        if (authnStatementEl == null) return null;
        String idx = authnStatementEl.getAttribute("SessionIndex");
        return (idx == null || idx.isBlank()) ? null : idx.trim();
    }

    private Conditions extractConditions(Element assertionEl) {
        Element conditionsEl = firstElementByLocalName(assertionEl, "Conditions");
        if (conditionsEl == null) return new Conditions(null, null);

        Instant notBefore = parseInstantAttr(conditionsEl, "NotBefore");
        Instant notOnOrAfter = parseInstantAttr(conditionsEl, "NotOnOrAfter");
        return new Conditions(notBefore, notOnOrAfter);
    }

    private String extractAudience(Element assertionEl) {
        Element conditionsEl = firstElementByLocalName(assertionEl, "Conditions");
        if (conditionsEl == null) return null;
        Element audienceRestrictionEl = firstElementByLocalName(conditionsEl, "AudienceRestriction");
        if (audienceRestrictionEl == null) return null;
        Element audienceEl = firstElementByLocalName(audienceRestrictionEl, "Audience");
        if (audienceEl == null) return null;
        String v = audienceEl.getTextContent();
        return v == null ? null : v.trim();
    }

    private Map<String, List<String>> extractAttributes(Element assertionEl) {
        Map<String, List<String>> out = new LinkedHashMap<>();
        NodeList attrStatements = assertionEl.getElementsByTagNameNS("*", "AttributeStatement");
        for (int i = 0; i < attrStatements.getLength(); i++) {
            Node n = attrStatements.item(i);
            if (n.getNodeType() != Node.ELEMENT_NODE) continue;
            Element stmt = (Element) n;

            NodeList attrs = stmt.getElementsByTagNameNS("*", "Attribute");
            for (int j = 0; j < attrs.getLength(); j++) {
                Node an = attrs.item(j);
                if (an.getNodeType() != Node.ELEMENT_NODE) continue;
                Element attrEl = (Element) an;

                String name = attrEl.getAttribute("Name");
                if (name == null || name.isBlank()) {
                    name = attrEl.getAttribute("FriendlyName");
                }
                if (name == null || name.isBlank()) continue;

                List<String> values = new ArrayList<>();
                NodeList valueNodes = attrEl.getElementsByTagNameNS("*", "AttributeValue");
                for (int k = 0; k < valueNodes.getLength(); k++) {
                    Node vn = valueNodes.item(k);
                    if (vn.getNodeType() != Node.ELEMENT_NODE) continue;
                    String v = vn.getTextContent();
                    if (v != null) {
                        v = v.trim();
                        if (!v.isEmpty()) values.add(v);
                    }
                }
                if (!values.isEmpty()) {
                    out.computeIfAbsent(name, __ -> new ArrayList<>()).addAll(values);
                }
            }
        }
        out.replaceAll((k, v) -> List.copyOf(v));
        return out;
    }

    private Instant parseInstantAttr(Element el, String attr) {
        String v = el.getAttribute(attr);
        if (v == null || v.isBlank()) return null;
        try {
            return Instant.parse(v.trim());
        } catch (Exception e) {
            return null;
        }
    }

    private String textOfFirst(Element scope, String localName) {
        Element el = firstElementByLocalName(scope, localName);
        if (el == null) return null;
        String v = el.getTextContent();
        return v == null ? null : v.trim();
    }

    private Element firstElementByLocalName(Node scope, String localName) {
        if (scope instanceof Document d) {
            NodeList list = d.getElementsByTagNameNS("*", localName);
            return list.getLength() == 0 ? null : (Element) list.item(0);
        }
        if (scope instanceof Element e) {
            NodeList list = e.getElementsByTagNameNS("*", localName);
            return list.getLength() == 0 ? null : (Element) list.item(0);
        }
        return null;
    }

    private static final class Conditions {
        final Instant notBefore;
        final Instant notOnOrAfter;

        private Conditions(Instant notBefore, Instant notOnOrAfter) {
            this.notBefore = notBefore;
            this.notOnOrAfter = notOnOrAfter;
        }
    }
}

