package com.example.samlsp.session;

import com.example.samlsp.controller.SamlAcsController;
import com.example.samlsp.saml.SamlAuthentication;
import com.example.samlsp.saml.SamlResponseProcessor;
import jakarta.servlet.*;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;

import java.io.IOException;
import java.util.Set;

public class SessionAuthInterceptor implements Filter {

    private static final Set<String> PUBLIC_PATH_PREFIXES = Set.of(
            "/saml/acs",
            "/error",
            "/actuator"
    );

    private final SamlResponseProcessor processor;

    public SessionAuthInterceptor(SamlResponseProcessor processor) {
        this.processor = processor;
    }

    @Override
    public void doFilter(ServletRequest req, ServletResponse res, FilterChain chain) throws IOException, ServletException {
        HttpServletRequest request = (HttpServletRequest) req;
        HttpServletResponse response = (HttpServletResponse) res;

        String path = request.getRequestURI();
        if (isPublic(path) || isStatic(path)) {
            chain.doFilter(req, res);
            return;
        }

        HttpSession session = request.getSession(false);
        SamlAuthentication auth = (session == null) ? null : (SamlAuthentication) session.getAttribute(SamlAcsController.SESSION_AUTH_KEY);
        if (auth == null) {
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            response.setContentType("text/plain;charset=UTF-8");
            response.getWriter().write("Unauthorized");
            return;
        }

        chain.doFilter(req, res);
    }

    private boolean isPublic(String path) {
        if (path == null) return true;
        for (String p : PUBLIC_PATH_PREFIXES) {
            if (path.startsWith(p)) return true;
        }
        return false;
    }

    private boolean isStatic(String path) {
        if (path == null) return false;
        return path.startsWith("/static/") || path.startsWith("/css/") || path.startsWith("/js/") || path.startsWith("/images/") || path.equals("/favicon.ico");
    }
}

package com.example.samlsp.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class HomeController {

    @GetMapping("/")
    public ResponseEntity<String> home(HttpServletRequest request) {
        HttpSession s = request.getSession(false);
        if (s == null) return ResponseEntity.ok("Hello (no session)");
        Object nameId = s.getAttribute("SAML_NAME_ID");
        return ResponseEntity.ok("Hello " + (nameId == null ? "user" : nameId.toString()));
    }
}

